import React, { useRef, useCallback } from 'react'

function useDebounce({cb, delay = 500}) {
  const timerRef = null
    return useCallback((...args) => {
      if(timerRef.current) {
      clearTimeout(timerRef.current)
      }
      timerRef.current = setTimeout(() => {
         cb(...args)
      }, delay)
    },[cb,delay])
}

export default React.memo(useDebounce)
